129	func queueTargetRank(desired []Bead, targetID string) (int, bool) {
130		targetIdx := -1
131		for i, bead := range desired {
132			if bead.ID == targetID {
133				targetIdx = i
134				break
135			}
136		}
137		if targetIdx < 0 {
138			return 0, false
139		}
140	
141		for i := 0; i < targetIdx; i++ {
142			if _, ok := parseQueueRank(desired[i].Extra[queueRankKey]); !ok {
143				return 0, false
144			}
145		}
146	
147		var prevRank *int
148		for i := targetIdx - 1; i >= 0; i-- {
149			if rank, ok := parseQueueRank(desired[i].Extra[queueRankKey]); ok {
150				prevRank = &rank
151				break
152			}
153		}
154	
155		var nextRank *int
156		for i := targetIdx + 1; i < len(desired); i++ {
157			if rank, ok := parseQueueRank(desired[i].Extra[queueRankKey]); ok {
158				nextRank = &rank
159				break
160			}
161		}
162	
163		switch {
164		case prevRank != nil && nextRank != nil:
165			if *nextRank-*prevRank <= 1 {
166				return 0, false
167			}
168			return (*prevRank + *nextRank) / 2, true
169		case prevRank != nil:
170			return *prevRank + 1, true
171		case nextRank != nil:
172			return *nextRank - 1, true
173		default:
174			return 0, true
175		}
176	}
